#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=55;
int n,a,b,mx[N][N],mn[N][N],ans1,ans2,ans3;
void floyd()
{
	for(int k=1;k<=n;k++)
	{
		for(int i=1;i<=n;i++)
		{
			for(int j=1;j<=n;j++)
			{
				mx[i][j]=min(mx[i][j],mx[i][k]+mx[k][j]);
				mn[i][j]=max(mn[i][j],mn[i][k]+mn[k][j]);
			}
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>a>>b;
	for(int i=1;i<=n;i++)
	{
		string s;
		cin>>s;
		s=" "+s;
		for(int j=1;j<=n;j++)
		{
			char c=s[j];
			if((i==j)||(c=='=')) mx[i][j]=mn[i][j]=0;
			else if(c=='+') mx[i][j]=2,mn[i][j]=1;
			else if(c=='-') mx[i][j]=-1,mn[i][j]=-2;
			else mx[i][j]=2,mn[i][j]=-2;
		}
	}
	floyd();
	for(int i=1;i<=n;i++)
	{
		if((i==a)||(i==b)) continue;
		for(int j=1;j<i;j++)
		{
			if((j==a)||(j==b)) continue;
			if((mn[a][i]>mx[j][b])||(mn[a][j]>mx[i][b])) ans1++;
			if((mn[a][i]==mx[a][i]&&mn[a][i]==mn[j][b]&&mn[j][b]==mx[j][b])||
			(mn[b][i]==mx[b][i]&&mn[b][i]==mn[j][a]&&mn[j][a]==mx[j][a])) ans2++;
			if((mx[a][i]<mn[j][b])||(mx[a][j]<mn[i][b])) ans3++;
		}
	}
	cout<<ans1<<" "<<ans2<<" "<<ans3;
	return 0;
}
